-- =====================================================
-- 历史事件卡池导入脚本
-- arbitrary-gate
-- 数据库: arbitrary_gate
-- 说明: 导入 600+ 历史事件卡牌，按朝代分类
-- 稀有度: 1=凡品, 2=珍品, 3=奇品, 4=绝品
-- =====================================================

USE `arbitrary_gate`;

-- ---------------------------------------------------
-- 步骤1: 更新表结构，添加新字段
-- ---------------------------------------------------
ALTER TABLE `event_card`
  ADD COLUMN IF NOT EXISTS `year` INT DEFAULT NULL COMMENT '事件年份（负数表示公元前）' AFTER `dynasty`,
  ADD COLUMN IF NOT EXISTS `latitude` DECIMAL(9,6) DEFAULT NULL COMMENT '事件纬度' AFTER `year`,
  ADD COLUMN IF NOT EXISTS `longitude` DECIMAL(9,6) DEFAULT NULL COMMENT '事件经度' AFTER `latitude`,
  ADD COLUMN IF NOT EXISTS `rarity` TINYINT UNSIGNED NOT NULL DEFAULT 1 COMMENT '稀有度: 1=凡, 2=珍, 3=奇, 4=绝' AFTER `description`,
  ADD COLUMN IF NOT EXISTS `identity_options` JSON DEFAULT NULL COMMENT '三种身份视角配置' AFTER `rarity`;

-- ---------------------------------------------------
-- 步骤2: 清空旧数据（可选，保留则注释掉下一行）
-- ---------------------------------------------------
DELETE FROM `event_card`;

-- ---------------------------------------------------
-- 步骤3: 导入历史事件数据（600+条）
-- 按朝代分类：先秦/秦汉/三国/隋唐/宋元/明清/近代/虚构传说
-- ---------------------------------------------------

-- >>> 先秦（约公元前2070-公元前221）
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `year`, `location`, `latitude`, `longitude`, `description`, `rarity`, `identity_options`) VALUES
-- 传说时代
('EV031','黄河·大禹治水','先秦',-2100,'黄河流域',35.7563,114.3523,'大禹疏导江河，三过家门而不入，开启夏朝文明',4,'[{"identity":"天子","perspective":"你是夏禹，站在黄河决堤处，看万民流离，誓要驯服水患。"},{"identity":"庶民","perspective":"你是河两岸的百姓，年年洪涝，田庐漂没，只盼有人能治水。"},{"identity":"方士","perspective":"你是观测天象的方士，星象异动，大水将至，禹能成功吗？"}]'),
('EV032','涂山·夏启继位','先秦',-2000,'涂山',32.6276,116.9748,'禹传位于启，家天下之始，中国第一个世袭王朝',3,'[{"identity":"贵族","perspective":"你是禹身边的贵族，禅让传统被打破，权力的滋味令人沉醉。"},{"identity":"巫祝","perspective":"你是涂山的祭司，涂山之会是天命转移的仪式。"},{"identity":"方国使节","perspective":"你是四方来贺的使节，看着这新王朝气象，心中满是疑虑。"}]'),
('EV033','钧台·启享万邦','先秦',-1990,'钧台',34.7872,113.6518,'夏启大会诸侯于钧台，中国进入青铜时代',2,'[{"identity":"诸侯","perspective":"你是四方诸侯，钧台之下，万国来朝，启的权威无可置疑。"},{"identity":"乐师","perspective":"你是宫廷乐师，九歌韶舞，天子宫廷的礼乐正在成形。"},{"identity":"青铜匠","perspective":"你是青铜匠人，铸鼎象物，鼎是王权的象征。"}]'),
('EV034','斟鄩·羿代夏政','先秦',-1940,'斟鄩',35.2962,113.2279,'后羿趁夏王太康出游，篡夺夏政，史称太康失国',3,'[{"identity":"太康","perspective":"你是被逐的夏王太康，在斟鄩的宫殿里醉生梦死，不知大难将至。"},{"identity":"后羿","perspective":"你是后羿，弯弓射日的神话英雄，如今要夺取这天下。"},{"identity":"老臣","perspective":"你是夏朝老臣，眼睁睁看着羿代夏政，却无能为力。"}]'),
('EV035','商丘·商汤革命','先秦',-1600,'商丘',34.7458,115.6657,'成汤伐夏，鸣条之战，夏朝覆灭，商朝建立',4,'[{"identity":"成汤","perspective":"你是商族领袖成汤，夏桀无道，你誓要吊民伐罪。"},{"identity":"伊尹","perspective":"你是商汤的相国伊尹，鼎鼐调和，辅助明君。"},{"identity":"夏桀","perspective":"你是夏桀，琼台瑶榭，酒池肉林，不知末日将至。"}]'),
('EV036','亳都·盘庚迁殷','先秦',-1300,'亳都',36.1026,114.3936,'盘庚迁都于殷，克服贵族阻力，商朝中興',3,'[{"identity":"盘庚","perspective":"你是商王盘庚，迁都艰难，但为了商朝的长远，你必须坚持。"},{"identity":"贵族","perspective":"你是反对迁都的贵族，祖宗的宗庙在亳，搬迁是背叛。"},{"identity":"平民","perspective":"你是被迫迁徙的平民，离开故土，前路未知。"}]'),
('EV037','殷墟·武丁盛世','先秦',-1250,'殷墟',36.1100,114.3500,'武丁在位59年，商朝鼎盛，甲骨文鼎盛时期',3,'[{"identity":"武丁","perspective":"你是商王武丁，夜梦贤臣，傅说版筑，励精图治。"},{"identity":"妇好","perspective":"你是武丁的王后妇好，率军征战，是最早的女将军。"},{"identity":"贞人","perspective":"你是贞人，用甲骨占卜，记录商王的每一道命令。"}]'),
('EV038','牧野·武王伐纣','先秦',-1046,'牧野',33.4286,115.3819,'周武王伐商，牧野之战，纣王鹿台自焚，商周换代',4,'[{"identity":"周武王","perspective":"你是姬发，率诸侯联军，陈兵牧野，讨伐无道的纣王。"},{"identity":"纣王","perspective":"你是帝辛，鹿台之上，鹿台倾颓，你点燃了最后的火焰。"},{"identity":"姜子牙","perspective":"你是姜子牙，直钩钓鱼，等来了周文王，辅佐武王伐纣。"}]'),
